// ── Slider functions ──
function sliderToYear(v){
  v=parseInt(v);
  return Math.round(-8000+(v/1000)*(2024-(-8000)));
}
function yearToSlider(yr){
  yr=parseInt(yr);
  return Math.round(((yr-(-8000))/(2024-(-8000)))*1000);
}

